class Solution {
    public boolean possibleBipartition(int n, int[][] dislikes) {
        int[] color = new int[n + 1];
        Map<Integer, List<Integer>> graph = new HashMap<>();

        for (int[] dislike : dislikes) {
            graph.computeIfAbsent(dislike[0], k -> new ArrayList<>()).add(dislike[1]);
            graph.computeIfAbsent(dislike[1], k -> new ArrayList<>()).add(dislike[0]);
        }

        for (int i = 1; i <= n; i++) {
            if (color[i] == 0 && !dfs(graph, color, i, 1)) {
                return false;
            }
        }
        return true;
    }

    private boolean dfs(Map<Integer, List<Integer>> graph, int[] color, int node, int currColor) {
        color[node] = currColor;
        for (int neighbor : graph.getOrDefault(node, Collections.emptyList())) {
            if (color[neighbor] == currColor) {
                return false;
            }
            if (color[neighbor] == 0 && !dfs(graph, color, neighbor, -currColor)) {
                return false;
            }
        }
        return true;
    }
}
